const tenant = $json;
const GEMINI_KEY = $env.GOOGLE_GEMINI_API_KEY || '';
if (!GEMINI_KEY) return { tenant_id: tenant.tenant_id, skip: true, error: 'NO_KEY' };

const specialty = tenant.speciality || 'Medicina';
const doctorName = tenant.doctor_name || '';
const city = tenant.city || '';

const dayOfWeek = new Date().getDay();
const postTypes = [
  { type: 'educational', topic: 'tema educativo relevante de ' + specialty },
  { type: 'myth_vs_fact', topic: 'mito vs fato sobre ' + specialty },
  { type: 'health_tip', topic: 'dica pratica de saude sobre ' + specialty },
  { type: 'seasonal', topic: 'cuidados sazonais relacionados a ' + specialty },
  { type: 'service_highlight', topic: 'importancia de consultas preventivas em ' + specialty }
];
const selected = postTypes[dayOfWeek % postTypes.length];

const systemPrompt = 'Voce e um especialista em marketing medico + design para Instagram. REGRAS: 1) NUNCA prometa cura. 2) NUNCA use antes/depois. 3) Tom profissional e acolhedor. 4) Max 280 chars no post_text. 5) 5-8 hashtags. 6) image_prompt deve descrever uma imagem ABSTRATA/ILUSTRATIVA (nunca rostos humanos reais, nunca fotos de pacientes). Use ilustracoes flat, icones medicos, cores suaves. 7) SOMENTE JSON valido, sem markdown.';

const userPrompt = 'Crie um post de Instagram sobre: ' + selected.topic + '. Para ' + doctorName + (city ? ' em ' + city : '') + '. Responda em JSON: {"post_text": "texto do post max 280 chars", "hashtags": ["tag1","tag2","tag3","tag4","tag5"], "post_type": "' + selected.type + '", "image_prompt": "descricao detalhada da imagem em ingles, estilo flat illustration, medical theme, soft colors, no human faces"}';

try {
  const resp = await fetch('https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key=' + GEMINI_KEY, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      contents: [{ parts: [{ text: userPrompt }] }],
      systemInstruction: { parts: [{ text: systemPrompt }] },
      generationConfig: { temperature: 0.85, maxOutputTokens: 600 }
    })
  });
  const data = await resp.json();
  const raw = (data.candidates?.[0]?.content?.parts?.[0]?.text || '').replace(/```json/g,'').replace(/```/g,'').trim();

  let parsed;
  try { parsed = JSON.parse(raw); } catch {
    const m = raw.match(/\{[\s\S]*\}/);
    parsed = m ? JSON.parse(m[0]) : { post_text: raw, hashtags: [], post_type: selected.type, image_prompt: '' };
  }

  return {
    tenant_id: tenant.tenant_id,
    post_text: parsed.post_text || '',
    hashtags: parsed.hashtags || [],
    post_type: parsed.post_type || selected.type,
    image_prompt: parsed.image_prompt || 'minimalist medical illustration, soft blue and white colors, healthcare theme, flat design, no text',
    platform: 'instagram',
    specialty_topic: specialty,
    ai_model: 'gemini-2.0-flash',
    skip: false
  };
} catch (e) {
  return { tenant_id: tenant.tenant_id, skip: true, error: e.message };
}

const item = $json;
if (item.skip) return item;

const GEMINI_KEY = $env.GOOGLE_GEMINI_API_KEY || '';
if (!GEMINI_KEY) return { ...item, post_image_url: null, image_error: 'NO_KEY' };

const prompt = item.image_prompt + '. Instagram post format, 1080x1080px, high quality, professional medical branding.';

try {
  // Try Imagen 3 via Gemini API
  const resp = await fetch('https://generativelanguage.googleapis.com/v1beta/models/imagen-3.0-generate-002:predict?key=' + GEMINI_KEY, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      instances: [{ prompt: prompt }],
      parameters: {
        sampleCount: 1,
        aspectRatio: '1:1',
        safetyFilterLevel: 'block_medium_and_above'
      }
    })
  });

  if (!resp.ok) {
    // Fallback: gemini-2.0-flash with image generation
    const resp2 = await fetch('https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash-exp:generateContent?key=' + GEMINI_KEY, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        contents: [{ parts: [{ text: 'Generate an image: ' + prompt }] }],
        generationConfig: { responseModalities: ['IMAGE', 'TEXT'] }
      })
    });
    const d2 = await resp2.json();
    const imgPart = d2.candidates?.[0]?.content?.parts?.find(p => p.inlineData);
    if (imgPart) {
      return { ...item, post_image_base64: imgPart.inlineData.data, post_image_mime: imgPart.inlineData.mimeType };
    }
    return { ...item, post_image_url: null, image_error: 'No image in fallback' };
  }

  const data = await resp.json();
  const imgData = data.predictions?.[0]?.bytesBase64Encoded;
  if (imgData) {
    return { ...item, post_image_base64: imgData, post_image_mime: 'image/png' };
  }
  return { ...item, post_image_url: null, image_error: 'No image data' };
} catch (e) {
  return { ...item, post_image_url: null, image_error: e.message };
}

const item = $json;
if (item.skip || !item.post_image_base64) return { ...item, post_image_url: item.post_image_url || null };

const SUPABASE_URL = 'https://qwyxacfgoqlskidwzdxe.supabase.co';
const SUPABASE_KEY = $env.SUPABASE_SERVICE_KEY || '';

if (!SUPABASE_KEY) {
  return { ...item, post_image_url: null, image_note: 'SUPABASE_SERVICE_KEY nao configurada - imagem gerada mas nao salva' };
}

const fileName = item.tenant_id + '/' + Date.now() + '_' + item.post_type + '.png';
const binaryData = Buffer.from(item.post_image_base64, 'base64');

try {
  const resp = await fetch(SUPABASE_URL + '/storage/v1/object/post-images/' + fileName, {
    method: 'POST',
    headers: {
      'Authorization': 'Bearer ' + SUPABASE_KEY,
      'Content-Type': item.post_image_mime || 'image/png',
      'x-upsert': 'true'
    },
    body: binaryData
  });

  if (resp.ok) {
    const publicUrl = SUPABASE_URL + '/storage/v1/object/public/post-images/' + fileName;
    const cleaned = { ...item, post_image_url: publicUrl };
    delete cleaned.post_image_base64;
    return cleaned;
  }
  return { ...item, post_image_url: null, image_error: 'Upload failed: ' + resp.status, post_image_base64: undefined };
} catch (e) {
  return { ...item, post_image_url: null, image_error: e.message, post_image_base64: undefined };
}

